/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements template rendering, recipient validation, and email delivery
 * through a configurable transport. Uses an in-memory transport by default
 * for testing; inject a real transport (SMTP, SendGrid, SES) for production.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered email ready for delivery.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport interface for sending rendered emails.
 * Implement this to integrate with a real email provider.
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  /** Sender address for outgoing emails. */
  fromAddress: string;
  /** Application name used in templates. */
  appName: string;
  /** Optional custom transport. Defaults to in-memory transport. */
  transport?: EmailTransport;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflow.pro',
  appName: 'TaskFlow Pro',
};

/**
 * In-memory transport for testing — stores sent emails instead of delivering them.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: Array<RenderedEmail & { messageId: string }> = [];
  private nextId = 1;

  async sendMail(email: RenderedEmail): Promise<{ messageId: string }> {
    const messageId = `msg-${String(this.nextId++).padStart(4, '0')}`;
    this.sent.push({ ...email, messageId });
    return { messageId };
  }

  getSentMails(): Array<RenderedEmail & { messageId: string }> {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
    this.nextId = 1;
  }
}

/**
 * Template definitions keyed by notification type.
 * Each template receives the notification payload and returns rendered HTML and plain text.
 */
type TemplateRenderer = (payload: NotificationPayload, appName: string) => { html: string; text: string };

const TEMPLATES: Record<NotificationType, TemplateRenderer> = {
  'order:confirmation': (payload, appName) => {
    const html = [
      `<h1>Order Confirmation</h1>`,
      `<p>Hi there,</p>`,
      `<p>Thank you for your order!</p>`,
      `<div>${escapeHtml(payload.body)}</div>`,
      `<p>If you have any questions, please contact our support team.</p>`,
      `<footer><small>${escapeHtml(appName)}</small></footer>`,
    ].join('\n');

    const text = [
      'Order Confirmation',
      '',
      'Hi there,',
      'Thank you for your order!',
      '',
      payload.body,
      '',
      `If you have any questions, please contact our support team.`,
      `— ${appName}`,
    ].join('\n');

    return { html, text };
  },

  'order:status-update': (payload, appName) => {
    const html = [
      `<h1>Order Status Update</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      `<p>You can check your order details in your account dashboard.</p>`,
      `<footer><small>${escapeHtml(appName)}</small></footer>`,
    ].join('\n');

    const text = [
      'Order Status Update',
      '',
      payload.body,
      '',
      'You can check your order details in your account dashboard.',
      `— ${appName}`,
    ].join('\n');

    return { html, text };
  },

  'user:welcome': (payload, appName) => {
    const html = [
      `<h1>Welcome to ${escapeHtml(appName)}!</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      `<p>Get started by exploring your dashboard.</p>`,
      `<footer><small>${escapeHtml(appName)}</small></footer>`,
    ].join('\n');

    const text = [
      `Welcome to ${appName}!`,
      '',
      payload.body,
      '',
      'Get started by exploring your dashboard.',
      `— ${appName}`,
    ].join('\n');

    return { html, text };
  },

  'user:profile-updated': (payload, appName) => {
    const html = [
      `<h1>Profile Updated</h1>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      `<footer><small>${escapeHtml(appName)}</small></footer>`,
    ].join('\n');

    const text = [
      'Profile Updated',
      '',
      payload.body,
      `— ${appName}`,
    ].join('\n');

    return { html, text };
  },
};

/**
 * Escape HTML special characters to prevent injection in rendered templates.
 */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Validate that a string looks like a plausible email address.
 */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private transport: EmailTransport;
  private sentEmails: NotificationPayload[] = [];

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.transport = this.config.transport ?? new InMemoryTransport();
  }

  /**
   * Send an email notification.
   *
   * Validates the recipient, renders the appropriate template, and delivers
   * through the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    // Validate recipient
    const recipient = this.resolveRecipient(payload.recipient);
    if (!recipient) {
      const error = `Invalid email recipient: ${payload.recipient}`;
      this.logger.error(error);
      return {
        notificationId: payload.id,
        channel: this.channel,
        success: false,
        error,
        deliveredAt: new Date(),
      };
    }

    // Render template
    const rendered = this.renderTemplate(payload);

    // Build the email
    const email: RenderedEmail = {
      to: recipient,
      from: this.config.fromAddress,
      subject: payload.subject,
      html: rendered.html,
      text: rendered.text,
    };

    try {
      const result = await this.transport.sendMail(email);
      this.logger.info(`Email delivered: ${result.messageId} to ${recipient}`);

      this.sentEmails.push(payload);

      return {
        notificationId: payload.id,
        channel: this.channel,
        success: true,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const error = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Email delivery failed for ${payload.id}: ${error}`);
      return {
        notificationId: payload.id,
        channel: this.channel,
        success: false,
        error,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Resolve and validate the recipient email address.
   * Returns the validated email or null if invalid.
   */
  resolveRecipient(recipient: string): string | null {
    const trimmed = recipient.trim().toLowerCase();
    if (!isValidEmail(trimmed)) {
      return null;
    }
    return trimmed;
  }

  /**
   * Render the notification body using the template for its type.
   */
  renderTemplate(payload: NotificationPayload): { html: string; text: string } {
    const renderer = TEMPLATES[payload.type];
    return renderer(payload, this.config.appName);
  }

  /**
   * Get all successfully sent emails (useful for testing).
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  type EmailTransport,
  type RenderedEmail,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order:confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date(),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter({ transport });
  });

  describe('send', () => {
    it('should deliver an email through the transport', async () => {
      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');

      const sent = transport.getSentMails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
    });

    it('should use configured from address', async () => {
      adapter = new EmailAdapter({
        transport,
        fromAddress: 'support@myapp.com',
      });

      await adapter.send(createPayload());

      const sent = transport.getSentMails();
      expect(sent[0]?.from).toBe('support@myapp.com');
    });

    it('should use default from address when not configured', async () => {
      await adapter.send(createPayload());

      const sent = transport.getSentMails();
      expect(sent[0]?.from).toBe('noreply@taskflow.pro');
    });

    it('should track sent emails', async () => {
      await adapter.send(createPayload());
      await adapter.send(createPayload({ id: 'notif-0002', recipient: 'bob@example.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(createPayload());
      adapter.clearSentEmails();

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should fail for invalid recipient', async () => {
      const payload = createPayload({ recipient: 'not-an-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email recipient');
      expect(transport.getSentMails()).toHaveLength(0);
    });

    it('should fail for empty recipient', async () => {
      const payload = createPayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw new Error('SMTP connection refused');
        },
      };

      adapter = new EmailAdapter({ transport: failingTransport });
      const result = await adapter.send(createPayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should handle non-Error transport throws', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw 'string error';
        },
      };

      adapter = new EmailAdapter({ transport: failingTransport });
      const result = await adapter.send(createPayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown transport error');
    });
  });

  describe('resolveRecipient', () => {
    it('should normalize email to lowercase', () => {
      expect(adapter.resolveRecipient('Alice@Example.COM')).toBe('alice@example.com');
    });

    it('should trim whitespace', () => {
      expect(adapter.resolveRecipient('  alice@example.com  ')).toBe('alice@example.com');
    });

    it('should return null for invalid email', () => {
      expect(adapter.resolveRecipient('not-an-email')).toBeNull();
      expect(adapter.resolveRecipient('@missing-local.com')).toBeNull();
      expect(adapter.resolveRecipient('missing-domain@')).toBeNull();
      expect(adapter.resolveRecipient('')).toBeNull();
    });

    it('should accept valid emails', () => {
      expect(adapter.resolveRecipient('user@domain.com')).toBe('user@domain.com');
      expect(adapter.resolveRecipient('user+tag@domain.co.uk')).toBe('user+tag@domain.co.uk');
    });
  });

  describe('renderTemplate', () => {
    it('should render order confirmation template', () => {
      const payload = createPayload({ type: 'order:confirmation' });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Order Confirmation');
      expect(rendered.html).toContain('Thank you for your order');
      expect(rendered.text).toContain('Order Confirmation');
      expect(rendered.text).toContain('Thank you for your order');
    });

    it('should render order status update template', () => {
      const payload = createPayload({
        type: 'order:status-update',
        body: 'Your order status has changed from pending to confirmed.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Order Status Update');
      expect(rendered.text).toContain('pending to confirmed');
    });

    it('should render user welcome template', () => {
      const payload = createPayload({
        type: 'user:welcome',
        body: 'Welcome aboard!',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Welcome to TaskFlow Pro');
      expect(rendered.text).toContain('Welcome to TaskFlow Pro');
    });

    it('should render user profile-updated template', () => {
      const payload = createPayload({
        type: 'user:profile-updated',
        body: 'Your profile has been updated.',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Profile Updated');
      expect(rendered.text).toContain('Your profile has been updated');
    });

    it('should use custom app name in templates', () => {
      adapter = new EmailAdapter({ transport, appName: 'MyApp' });
      const payload = createPayload({ type: 'user:welcome', body: 'Hi!' });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('Welcome to MyApp');
      expect(rendered.text).toContain('MyApp');
    });

    it('should escape HTML in body content', () => {
      const payload = createPayload({
        type: 'order:confirmation',
        body: '<script>alert("xss")</script>',
      });
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
    });

    it('should include both html and text versions', () => {
      const payload = createPayload();
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.html).toContain('<h1>');
      expect(rendered.text).not.toContain('<h1>');
    });
  });

  describe('InMemoryTransport', () => {
    it('should generate sequential message IDs', async () => {
      const t = new InMemoryTransport();
      const email: RenderedEmail = {
        to: 'a@b.com',
        from: 'x@y.com',
        subject: 'Test',
        html: '<p>Hi</p>',
        text: 'Hi',
      };

      const r1 = await t.sendMail(email);
      const r2 = await t.sendMail(email);

      expect(r1.messageId).toBe('msg-0001');
      expect(r2.messageId).toBe('msg-0002');
    });

    it('should store and retrieve sent mails', async () => {
      const t = new InMemoryTransport();
      await t.sendMail({
        to: 'a@b.com',
        from: 'x@y.com',
        subject: 'Test',
        html: '<p>Hi</p>',
        text: 'Hi',
      });

      expect(t.getSentMails()).toHaveLength(1);
      expect(t.getSentMails()[0]?.to).toBe('a@b.com');
    });

    it('should clear sent mails and reset counter', async () => {
      const t = new InMemoryTransport();
      await t.sendMail({
        to: 'a@b.com',
        from: 'x@y.com',
        subject: 'Test',
        html: '<p>Hi</p>',
        text: 'Hi',
      });

      t.clear();
      expect(t.getSentMails()).toHaveLength(0);

      const r = await t.sendMail({
        to: 'a@b.com',
        from: 'x@y.com',
        subject: 'Test',
        html: '<p>Hi</p>',
        text: 'Hi',
      });
      expect(r.messageId).toBe('msg-0001');
    });
  });
});
